import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecutionExample {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String userInput = reader.readLine();

        // Sanitize the user input by only allowing specific commands (e.g., "ping")
        if (!userInput.equals("ping")) {
            System.out.println("Invalid command. Only 'ping' command is allowed.");
            return;
        }

        // Execute the command using ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder(userInput);
        Process process = processBuilder.start();

        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = outputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

